export const uploadAttachment = async (uploadAttachmentBody: UploadAttachmentBody, options?: RequestInit): Promise<uploadAttachmentResponse> => {
    const formData = new FormData();
formData.append(`file`, uploadAttachmentBody.file);
if(uploadAttachmentBody.email_id !== undefined) {
 formData.append(`email_id`, uploadAttachmentBody.email_id.toString())
 }

  const res = await fetch(getUploadAttachmentUrl(),
  {
    ...options,
    method: 'POST'
    ,
    body:
      formData,
  }
)


  const body = [204, 205, 304].includes(res.status) ? null : await res.text();

  const data: uploadAttachmentResponse['data'] = body ? JSON.parse(body) : {}
  return { data, status: res.status, headers: res.headers } as uploadAttachmentResponse
}



