/**
 * Opens a server-sent event stream. Browser compatibility may pass the bearer token in the query string.
 * @summary Open SSE stream
 */
export type streamSSEResponse200 = {
  data: SseStreamResponse
  status: 200
}

export type streamSSEResponse401 = {
  data: UnauthorizedResponse
  status: 401
}

export type streamSSEResponseSuccess = (streamSSEResponse200) & {
  headers: Headers;
};
export type streamSSEResponseError = (streamSSEResponse401) & {
  headers: Headers;
};

export type streamSSEResponse = (streamSSEResponseSuccess | streamSSEResponseError)

export const getStreamSSEUrl = (params?: StreamSSEParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : value.toString())
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/v1/sse?${stringifiedParams}` : `/api/v1/sse`
}

export const streamSSE = async (params?: StreamSSEParams, options?: RequestInit): Promise<streamSSEResponse> => {

  const res = await fetch(getStreamSSEUrl(params),
  {
    ...options,
    method: 'GET'


  }
)


  const body = [204, 205, 304].includes(res.status) ? null : await res.text();

  const data: streamSSEResponse['data'] = body !== null ? body : ''
  return { data, status: res.status, headers: res.headers } as streamSSEResponse
}



